pub fn debug_csr_info() {
    let mut pgdl:usize= 0;
    let mut crmd:usize= 0;
    unsafe{
        asm!("csrrd {}, 0x19", out(reg) pgdl);
        asm!("csrrd {}, 0x0", out(reg) crmd);
    }
    debug!("pgdl: {:#x}, crmd: {:#b}", pgdl, crmd);
}

#[cfg(target_arch = "loongarch64")]
pub fn mem_test() {
    let aim1 = LOWRAM_BASE;
    let aim2 = LOWRAM_END;
    for addr in (aim1..aim2).step_by(8) {
        unsafe {
            let ptr = addr as *mut u64;
            ptr.write_volatile(0x12345678_9abcdeff);
            let val = ptr.read_volatile();
            assert_eq!(val, 0x12345678_9abcdeff);
        }
    }
    for addr in (aim1..aim2).step_by(8) {
        unsafe {
            let ptr = addr as *mut u64;
            ptr.write_volatile(0);
            let val = ptr.read_volatile();
            assert_eq!(val, 0);
        }
    }
    println!("mem_test passed!");
}

//! The panic handler

use crate::arch::sbi::shutdown;
use core::hint::spin_loop;
use core::panic::PanicInfo;
use core::sync::atomic::{AtomicBool, Ordering};

static PANICKING: AtomicBool = AtomicBool::new(false);

#[panic_handler]
fn panic(info: &PanicInfo) -> ! {
    if PANICKING.swap(true, Ordering::SeqCst) {
        // Avoid panic -> shutdown -> panic recursion storms.
        loop {
            spin_loop();
        }
    }

    if let Some(location) = info.location() {
        println!(
            "[kernel] Panicked at {}:{} {}",
            location.file(),
            location.line(),
            info.message()
        );
    } else {
        println!("[kernel] Panicked: {}", info.message());
    }

    println!("syncing disks...");
    crate::ext4fs::block_cache_sync_all();
    println!("shutting down...");
    shutdown(); // 调试时注释掉这行方便回溯调用栈
    loop{}
}

