    /// Get the indexes of the page table entry
    /// la64的页表索引顺序与SV39相同
    pub fn indexes(&self) -> [usize; 3] {
        let mut vpn = self.0;
        let mut idx = [0usize; 3];
        for i in (0..3).rev()/*翻转*/ {
            idx[i] = vpn & ((PAGE_SIZE>>3) - 1);
            vpn >>= PAGE_SIZE_BITS - 3;
        }
        idx
    }
}

