/// 页大小，单位Bytes
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum PageSize {
    Page4K = 1 << 12, // 4KB
    Page2M = 1 << ( 12 + 9 ), // 2MB
    Page1G = 1 << ( 12 + 9 + 9 ), // 1GB
}

impl PageSize {
    // 页大小对应的字节数
    pub fn size(&self) -> usize {
        self.clone() as usize
    }
    // 页大小对应的位数，如4KB对应12位
    pub fn size_bits(&self) -> usize {
        self.size().trailing_zeros() as usize
    }
    // 对应基本页的倍数
    pub fn num_pages(&self) -> usize {
        self.size() / PAGE_SIZE
    }
    // 页表层数，0表示根页表项直接映射
    pub fn walk_level(&self) -> usize {
        match self {
            PageSize::Page4K => 2,
            PageSize::Page2M => 1,
            PageSize::Page1G => 0,
        }
    }
}

