            state,
            smoltcp::socket::tcp::State::CloseWait | 
            smoltcp::socket::tcp::State::Closed | 
            smoltcp::socket::tcp::State::TimeWait | 
            smoltcp::socket::tcp::State::LastAck | 
            smoltcp::socket::tcp::State::Closing
