const VIRTIO0: usize = 0x10001000;
/// VirtIOBlock device driver strcuture for virtio_blk device
pub struct VirtIOBlock{
    pub inner: MPSafeCell<VirtIOBlk<'static, VirtioHal>>
}

lazy_static! {
    static ref QUEUE_FRAMES: MPSafeCell<Vec<FrameTracker>> = MPSafeCell::new(Vec::new());
}


impl VirtIOBlock {
    #[allow(unused)]
    pub fn new() -> Self {
        let mut blk_addr: usize = 0;

        // 和网卡一样，动态扫描 8 个槽位寻找磁盘
        for i in 1..=8 {
            let addr = 0x10000000 + 0x1000 * i;
            let header = unsafe { &mut *(addr as *mut VirtIOHeader) };

            if header.verify() && header.device_type() == DeviceType::Block {
                info!("[kernel] Found virtio-blk device at {:#x}", addr);
                blk_addr = addr;
                break;
            }
        }

        if blk_addr == 0 {
            panic!("[kernel] virtio-blk device not found!");
        }

        unsafe {
            Self { inner: MPSafeCell::new(
                VirtIOBlk::<VirtioHal>::new(&mut *(blk_addr as *mut VirtIOHeader)).unwrap(),
            ) }
        }
    }
}

pub struct VirtioHal;

impl Hal for VirtioHal {
    fn dma_alloc(pages: usize) -> usize {
        let mut ppn_base = PhysPageNum(0);
        for i in 0..pages {
            let frame = frame_alloc(crate::mm::PageSize::Page4K).unwrap();
            if i == 0 {
                ppn_base = frame.ppn;
            }
            // 这里假设frame_alloc分配的物理页是连续的
            // 可能有问题
            assert_eq!(frame.ppn.0, ppn_base.0 + i);
            QUEUE_FRAMES.exclusive_access().push(frame);
        }
        let pa: PhysAddr = ppn_base.into();
        pa.0
    }

    fn dma_dealloc(pa: usize, pages: usize) -> i32 {
        let pa = PhysAddr::from(pa);
        let mut ppn_base: PhysPageNum = pa.into();
        for _ in 0..pages {
            frame_dealloc(ppn_base, crate::mm::PageSize::Page4K);
            ppn_base.step();
        }
        0
    }

    fn phys_to_virt(addr: usize) -> usize {
        addr
    }

    fn virt_to_phys(vaddr: usize) -> usize {
        PageTable::from_token(kernel_token())
            .translate_va(VirtAddr::from(vaddr))
            .unwrap()
            .0
    }
}

use alloc::sync::{Arc, Weak};
use alloc::string::String;
use alloc::collections::BTreeMap;
use spin::Mutex;
use lazy_static::*;
use super::{VfsInode};

pub struct Dentry {
    pub name: String,
    pub inode: Arc<dyn VfsInode>,
    pub parent: Weak<Dentry>,
    pub children: Mutex<BTreeMap<String, Arc<Dentry>>>,
    pub mounted_children: Mutex<BTreeMap<String, Arc<Dentry>>>,
}

impl Dentry {
    pub fn new(
        name: String,
        inode: Arc<dyn VfsInode>,
        parent: Weak<Dentry>,
    ) -> Arc<Self> {
        Arc::new(Self {
            name,
            inode,
            parent,
            children: Mutex::new(BTreeMap::new()),
            mounted_children: Mutex::new(BTreeMap::new()),
        })
    }
    pub fn find(self: &Arc<Self>, name: &str) -> Arc<dyn VfsInode> {
        // 1. 挂载点优先
        let mounted_children = self.mounted_children.lock();
        if let Some(child) = mounted_children.get(name) {
            return child.inode.clone();
        }
        drop(mounted_children);

        // 2. 尝试从当前节点的缓存中获取
        let mut children = self.children.lock();
        if let Some(child) = children.get(name) {
            return child.inode.clone();
        }

        // 3. 缓存未击中，调用底层磁盘接口查找
        // 注意：这里调用 self.inode.find 是 VfsInode 特征定义的磁盘查找接口
        if let Some(vfs_inode) = self.inode.find(name) {
            // 找到了，将其包装成 Dentry 并插入缓存树
            let new_child = Self::new(
                String::from(name),
                vfs_inode.clone(),
                Arc::downgrade(self),
            );
            children.insert(String::from(name), new_child);
            return vfs_inode;
        }

        // 4. 磁盘也没找到，按照要求 panic
        panic!("VFS: File '{}' not found in directory '{}'", name, self.name);
    }

    /// 创建新节点，将其作为self的子节点插入树
    /// bug/特性：getdents不遍历children，只遍历mounted_children
    pub fn insert(self: &Arc<Self>, name: String, inode: Arc<dyn VfsInode>) -> Arc<Self> {
        let mut children = self.children.lock();
        if let Some(child) = children.get(&name) {
            return child.clone();
        }

        let new_child = Self::new(
            name.clone(),
            inode,
            Arc::downgrade(self), // 使用 Weak 防止循环引用
        );

        children.insert(name, new_child.clone());
        new_child
    }

    /// 在目前的实现中，专用于虚拟文件夹挂载
    /// bug/特性：getdents不遍历children，只遍历mounted_children
    pub fn mount_child(self: &Arc<Self>, name: String, inode: Arc<dyn VfsInode>) -> Arc<Self> {
        let mut mounted_children = self.mounted_children.lock();
        if let Some(child) = mounted_children.get(&name) {
            return child.clone();
        }

        let new_child = Self::new(
            name.clone(),
            inode,
            Arc::downgrade(self),
        );

        mounted_children.insert(name, new_child.clone());
