    pub fn find_tree(self: &Arc<Self>, path: &str, follow_links: bool) -> Result<Arc<Dentry>, usize> {
        if path.is_empty() {
            return Ok(self.clone());
        }
        // 1. 确定搜索起点
        let mut current = if path.starts_with('/') {
            ROOT_DENTRY.clone()
        } else {
            self.clone()
        };
