            let stat = next.inode.get_stat();
            let is_symlink = (stat.mode & 0o170000) == 0o120000; // S_IFLNK
            if is_symlink {
                let is_last_segment = components.is_empty();
                // 如果是最后一个路径分量且不需要追踪链接（对应 O_NOFOLLOW），直接返回软链接的 Dentry
                if is_last_segment && !follow_links {
