//! SBI console driver, for text output
use crate::arch::sbi::console_putchar;
use crate::sync::MPSafeCell;
use core::fmt::{self, Write};

use lazy_static::*;

lazy_static! {
    pub static ref CONSOLE_LOCK: MPSafeCell<()> = MPSafeCell::new(());
}

struct Stdout;

impl Write for Stdout {
    fn write_str(&mut self, s: &str) -> fmt::Result {
        for c in s.chars() {
            console_putchar(c as usize);
        }
        Ok(())
    }
}

pub fn print(args: fmt::Arguments) {
    let _lock = CONSOLE_LOCK.exclusive_access();
    // 这行会把fmt全部输出完
    Stdout.write_fmt(args).unwrap();
    drop(_lock);
}

/// Print! to the host console using the format string and arguments.
#[macro_export]
macro_rules! print {
    ($fmt: literal $(, $($arg: tt)+)?) => {
        $crate::console::print(format_args!($fmt $(, $($arg)+)?))
    }
}

/// Println! to the host console using the format string and arguments.
#[macro_export]
macro_rules! println {
    ($fmt: literal $(, $($arg: tt)+)?) => {
        #[allow(unreachable_code)]
        $crate::console::print(format_args!(concat!($fmt, "\n") $(, $($arg)+)?))
    }
}

//! loop设备支持
//! 如下摘自https://blog.csdn.net/zhongbeida_xue/article/details/109657639
//! Loop设备是一种块设备，但是它并不指向硬盘或者光驱，而是指向一个文件块或者另一种块设备。
//! 一种应用的例子：将另外一种文件系统的镜像文件保存到一个文件中，例如iso文件，然后将一个Loop设备指向该文件，
//! 紧接着就可以通过mount挂载该loop设备到主文件系统的一个目录下了，我们就可以正常访问该镜像中的内容，
//! 就像访问一个文件系统一样。

